import{_ as e,c as t,o,a as r}from"./app.2cb13ea6.js";const g='{"title":"Intro","titleTemplate":"Privacy, Security and Anonymity","description":"How to protect yourself from the internet, on the internet","frontmatter":{"title":"Intro","description":"How to protect yourself from the internet, on the internet","editLink":true,"titleTemplate":"Privacy, Security and Anonymity"},"headers":[{"level":2,"title":"Intro","slug":"intro-1"},{"level":2,"title":"Why should I care?","slug":"why-should-i-care"},{"level":2,"title":"PSA - Privacy, Security and Anonymity","slug":"psa-privacy-security-and-anonymity"},{"level":2,"title":"Open source everything","slug":"open-source-everything"},{"level":2,"title":"Encryption","slug":"encryption"},{"level":3,"title":"Why is encryption important?","slug":"why-is-encryption-important"},{"level":3,"title":"The green lock","slug":"the-green-lock"},{"level":3,"title":"End-to-end encryption (e2ee)","slug":"end-to-end-encryption-e2ee"},{"level":2,"title":"Metadata","slug":"metadata"},{"level":3,"title":"What is it?","slug":"what-is-it"},{"level":3,"title":"Why should I care?","slug":"why-should-i-care-1"},{"level":3,"title":"What can I do?","slug":"what-can-i-do"},{"level":2,"title":"Get your info here","slug":"get-your-info-here"}],"relativePath":"psa/intro.md","lastUpdated":1655106162000}',a={name:"psa/intro.md"},n=r('<h1 id="intro" tabindex="-1">Intro <a class="header-anchor" href="#intro" aria-hidden="true">#</a></h1><p><strong>How to protect yourself from the internet, on the internet</strong></p><p>Last updated on: 2022-05-28</p><h2 id="intro-1" tabindex="-1">Intro <a class="header-anchor" href="#intro-1" aria-hidden="true">#</a></h2><p>I&#39;ve really gotten into this stuff over the last year or so. I probably shouldn&#39;t have, since I had a lot of (arguably) more important stuff going on during that time, and focusing on that might have been better for me and my future. But I digress.</p><p>A lot of the stuff I say here might end up sounding like I live in the woods with a tinfoil hat, but I promise you at least 90% of the things I say here are true as of posting this. I also want to make sure you know, a lot of the stuff mentioned here will probably change someday, whereas this post will probably not be updated often, if at all. So be sure that the information you&#39;re getting is up to date. I&#39;ll link a few good sources of information at the bottom that can help you stay up-to-date on your privacy and security knowledge.</p><p>If you have any updates or changes you&#39;d like to suggest, you can open an issue on the <a href="https://github.com/noClaps/blog" target="_blank" rel="noopener noreferrer">Git repo for this blog</a>.</p><h2 id="why-should-i-care" tabindex="-1">Why should I care? <a class="header-anchor" href="#why-should-i-care" aria-hidden="true">#</a></h2><p>The online world is both a wonderful and terrible place. On one hand, you have <a href="https://www.livescience.com/54094-how-big-is-the-internet.html" target="_blank" rel="noopener noreferrer">more information available in the blink of an eye</a> than any library or school would ever be able to provide. You have a way to connect with people instantaneously through mediums like instant messaging or e-mail, discuss topics with thousands or millions of people at once on online forums and communities. You can display your talents to an audience so large it&#39;s mind-boggling. There are many, many improvements to everyday life that the internet has brought with it. It&#39;s never been easier to be completely free and uncensored.</p><p>As with everything, where there is a positive, there&#39;s a negative to rival it. There are constantly people and companies trying to take control of you and your behavior for their own benefit. Companies like Google, Facebook, Microsoft, Amazon, etc., all make <a href="https://www.visualcapitalist.com/how-big-tech-makes-their-billions-2020/" target="_blank" rel="noopener noreferrer">millions and millions of dollars</a> every year just from your personal information. And you don&#39;t get a penny of that back. Not only that, these companies have immense political power, mainly through <a href="https://www.cnbc.com/2020/01/22/how-much-google-facebook-amazon-and-apple-spent-on-lobbying-in-2019.html" target="_blank" rel="noopener noreferrer">lobbying</a> and collaborations with the US government in surveillance programs like <a href="https://en.wikipedia.org/wiki/PRISM_(surveillance_program)" target="_blank" rel="noopener noreferrer">PRISM</a>.</p><p>Along with that, there&#39;s manipulation for things <a href="https://en.wikipedia.org/wiki/Facebook%E2%80%93Cambridge_Analytica_data_scandal" target="_blank" rel="noopener noreferrer">as big as US presidential elections</a>, and danger for <a href="https://en.wikipedia.org/wiki/School_Strike_for_Climate#Censorship" target="_blank" rel="noopener noreferrer">activists</a>, <a href="https://en.wikipedia.org/wiki/Whistleblower#Risks" target="_blank" rel="noopener noreferrer">whistleblowers</a>, <a href="https://en.wikipedia.org/wiki/Lavabit#Suspension_and_gag_order" target="_blank" rel="noopener noreferrer">privacy-friendly services</a>, and more. While your situation may not be as extreme as these, it&#39;s always good to have control over your decisions, your information, and most importantly, your life.</p><p>This is especially true when <a href="https://www.theguardian.com/technology/2014/apr/15/gmail-scans-all-emails-new-google-terms-clarify" target="_blank" rel="noopener noreferrer">Gmail scans all of your emails</a>, <a href="https://joindeleteme.com/blog/does-facebook-sell-your-data/" target="_blank" rel="noopener noreferrer">Facebook tracks you and sells your data</a>, <a href="https://bgr.com/general/windows-10-upgrade-spying-how-to-opt-out/" target="_blank" rel="noopener noreferrer">Microsoft looks at pretty much everything you do on Windows</a>, <a href="https://www.consumerwatchdog.org/privacy-technology/how-google-and-amazon-are-spying-you" target="_blank" rel="noopener noreferrer">your Nest or Echo can hear almost everything you say at home</a>, and <a href="https://www.eff.org/deeplinks/2018/05/its-time-payment-processors-stripe-and-paypal-start-publishing-transparency" target="_blank" rel="noopener noreferrer">so</a>, <a href="https://nakedsecurity.sophos.com/2012/08/09/creepy-quora-erodes-users-privacy-reveals-what-you-have-read/" target="_blank" rel="noopener noreferrer">so</a> <a href="https://reddit.zendesk.com/hc/en-us/articles/360043048412-What-information-does-Reddit-collect-about-me-and-my-account-" target="_blank" rel="noopener noreferrer">many</a> <a href="https://www.usatoday.com/story/tech/news/2018/07/20/what-you-do-spotify-public-and-can-used-against-you/801647002/" target="_blank" rel="noopener noreferrer">more</a> <a href="https://news.sky.com/story/netflix-accused-of-spying-on-users-after-creepy-tweet-11167513" target="_blank" rel="noopener noreferrer">privacy</a> <a href="https://www.opensocietyfoundations.org/voices/amazon-is-waging-a-war-on-privacy" target="_blank" rel="noopener noreferrer">violations</a>.</p><p>Don&#39;t expect the government to come and save you either. The unfortunate part of all of this is that laws aren&#39;t able to catch up with the rapid development of the internet. In many cases, it&#39;s hindered by power-hungry politicians or greedy companies lobbying and manipulating said power-hungry politicians, making a never-ending loop of power and corruption. That leaves people like you and I in a state of helplessness, constantly being controlled and profited on, without getting any returns out of it.</p><p>I hope this explains why you should care about your own privacy. It&#39;s because <strong>no one else does</strong>.</p><h2 id="psa-privacy-security-and-anonymity" tabindex="-1">PSA - Privacy, Security and Anonymity <a class="header-anchor" href="#psa-privacy-security-and-anonymity" aria-hidden="true">#</a></h2><p>People often confuse these 3 terms, and while they can be interchangeable in a few situations, they are very different things and should be treated as such.</p><ul><li><a href="https://en.wikipedia.org/wiki/Privacy" target="_blank" rel="noopener noreferrer"><strong>Privacy</strong></a> is when you have control over your personal information and who can see it.</li><li><a href="https://en.wikipedia.org/wiki/Security" target="_blank" rel="noopener noreferrer"><strong>Security</strong></a> is when you have protection from unauthorized malicious actors.</li><li><a href="https://en.wikipedia.org/wiki/Anonymity" target="_blank" rel="noopener noreferrer"><strong>Anonymity</strong></a> is when you have a completely unknown/untraceable identity.</li></ul><p>It&#39;s possible to have one but not the others, and depending on what you&#39;re looking for, the tools you use will differ. For instance, <a href="https://www.torproject.org/" target="_blank" rel="noopener noreferrer"><abbr title="The Onion Router">Tor</abbr></a> is a much better tool for <strong>anonymity</strong>, whereas it&#39;s not as good as <a href="https://www.chromium.org/Home/" target="_blank" rel="noopener noreferrer">Chromium</a> for <strong>security</strong>, which is not as good as <a href="https://www.mozilla.org/en-US/firefox/new/" target="_blank" rel="noopener noreferrer">Firefox</a> for <strong>privacy</strong>.</p><p>There aren&#39;t many tools that&#39;ll give you privacy, security as well as anonymity, so make sure you know the difference between these 3 concepts, because it will really help you choose the right tools and services for the job. Also, whatever you choose, make sure it actually works for you, and you aren&#39;t just picking it because some nerd on the internet told you to. A lot of the time, people get frustrated with trying to achieve privacy because the things that internet strangers &quot;force&quot; them to use doesn&#39;t work for them, and they give up entirely.</p><p>In follow-up posts to this, I&#39;ll suggest some of the tools and services I&#39;ve heard of / used before, and how good or bad they are (according to me) for privacy and/or security. You don&#39;t have to listen to anything I say, and I encourage you to do your own research before making a decision. Try out different tools and services and see what works for you, before making a firm decision to use one.</p><hr><h2 id="open-source-everything" tabindex="-1">Open source everything <a class="header-anchor" href="#open-source-everything" aria-hidden="true">#</a></h2><p>Throughout my various posts on this topic, you may hear the term &quot;open source&quot; a lot. Other variations of this you may hear online are <abbr title="Open Source Software">OSS</abbr> (Open Source Software), <abbr title="Free and Open Source Software">FOSS</abbr> (Free and Open Source Software) or <abbr title="Free/Libre and Open Source Software">FLOSS</abbr> (Free/Libre and Open Source). They have some <a href="https://www.gnu.org/philosophy/floss-and-foss.en.html" target="_blank" rel="noopener noreferrer">slight differences</a> in their definitions, but for the most part they can be interchangeable.</p><p>Open source basically means you can see the source code of the app, program, service, etc., that you&#39;re using. An example of this is this blog, the Blog of Random. You can find the source <abbr title="HyperText Markup Language">HTML</abbr>, <abbr title="Cascading Style Sheets">CSS</abbr>, etc., for this blog at my <a href="https://github.com/noClaps/blog" target="_blank" rel="noopener noreferrer">GitHub</a>, linked up at the top. Another famous example of open source software is the <a href="https://firefox-source-docs.mozilla.org/contributing/directory_structure.html" target="_blank" rel="noopener noreferrer">Firefox</a> <a href="https://searchfox.org/mozilla-central/source" target="_blank" rel="noopener noreferrer">browser</a>.</p><p>Most of the apps and services I suggest will be mostly or fully open source, at least for the parts that actually matter. This is because open source is easier to &quot;trust&quot;, since any <a href="https://appleinsider.com/articles/21/07/04/open-source-audacity-deemed-spyware-over-data-collection-changes" target="_blank" rel="noopener noreferrer">malicious behavior can be relatively easily spotted</a>. I put &quot;trust&quot; in quotes because that&#39;s kind of the opposite of what we want. The purpose of open source software is to remove the need for trust entirely, because everything is clearly visible. Theoretically, anyone can go through the code, find something they don&#39;t like, and remove it in their fork (version) of the app. Practically, this isn&#39;t always possible because not everyone can understand code or audit effectively. Even in cases like this, having the source code be available helps transparency on the developer&#39;s end, making them just a little easier to trust.</p><p>Open source software can also have better privacy and security due to a theory called <a href="https://en.wikipedia.org/wiki/Linus%27s_law" target="_blank" rel="noopener noreferrer">Linus&#39;s law</a>. It states that open source software has many eyes on it, so bugs, vulnerabilities, or trackers are much easier to catch. It&#39;s important that I mention that this isn&#39;t always true, and there are many cases in which <a href="https://madaidans-insecurities.github.io/firefox-chromium.html" target="_blank" rel="noopener noreferrer">closed source software is more secure than open source</a>. The best way to ensure security, other than verifying it yourself by going through the source code, is to make sure the services you&#39;re using have been audited recently and have fixed any security vulnerabilities that have been found.</p><h2 id="encryption" tabindex="-1">Encryption <a class="header-anchor" href="#encryption" aria-hidden="true">#</a></h2><p>This is one of those big fancy &quot;security professional&quot; words that most people tell themselves they understand to look smart in front of their friends. And that&#39;s exactly what I&#39;m gonna do too, because I am by no means a security professional.</p><p>Encryption is important. It&#39;s what protects your stuff from being openly available to anyone on the internet. But not all encryption is equal, some kinds of encryption are better than others for certain purposes.</p><h3 id="why-is-encryption-important" tabindex="-1">Why is encryption important? <a class="header-anchor" href="#why-is-encryption-important" aria-hidden="true">#</a></h3><p>Imagine you&#39;re talking to your friend about something sensitive and personal to you. The only reason you&#39;re talking to them about it is because you trust them. Now imagine what it would feel like if someone was hiding, listening to your whole conversation, and then proceeded to tell everyone about this very personal thing that you didn&#39;t want anyone to know.</p><p>Having encryption is the equivalent of having a secret language that you and your friend made up and speak in. Whether that&#39;s something as simple as a <a href="https://en.wikipedia.org/wiki/Caesar_cipher" target="_blank" rel="noopener noreferrer">Caesar cipher</a>, or something as complex as <a href="https://en.wikipedia.org/wiki/Pretty_Good_Privacy" target="_blank" rel="noopener noreferrer"><abbr title="Pretty Good Privacy">PGP</abbr></a>, it&#39;s all a kind of encryption. Of course, <abbr title="Pretty Good Privacy">PGP</abbr> is a much stronger encryption protocol than a Caesar cipher, and there are better encryption protocols out there made specifically different things.</p><p>Many people will try to convince you that encryption is bad, and that you don&#39;t need encryption if you have <a href="https://en.wikipedia.org/wiki/Nothing_to_hide_argument" target="_blank" rel="noopener noreferrer">nothing to hide</a>. They&#39;ll make arguments like &quot;Removing encryption can help us catch criminals, like terrorists and pedophiles. THINK OF THE COUNTRY! THINK OF THE CHILDREN!&quot;, implying that anyone who uses encryption is a criminal that has something to hide. I don&#39;t support crime, but removing encryption entirely and spying on everyone seems to me like a &quot;guilty until proven innocent&quot; system. Also, the government wouldn&#39;t be the only one who would have access to your data, so would every hacker and bad internet person out there. There have even been cases where <a href="https://krebsonsecurity.com/2022/03/hackers-gaining-power-of-subpoena-via-fake-emergency-data-requests/" target="_blank" rel="noopener noreferrer">hackers posed as the police to get data from companies</a>!</p><p>Then again, these are the same people <a href="https://en.wikipedia.org/wiki/Mass_surveillance#By_country" target="_blank" rel="noopener noreferrer">running</a> <a href="https://en.wikipedia.org/wiki/PRISM_(surveillance_program)" target="_blank" rel="noopener noreferrer">mass</a> <a href="https://en.wikipedia.org/wiki/Five_Eyes" target="_blank" rel="noopener noreferrer">surveillance</a> <a href="https://www.businesstelegraph.co.uk/the-secret-police-cops-built-a-shadowy-surveillance-machine-in-minnesota-after-george-floyds-murder-mit-technology-review/" target="_blank" rel="noopener noreferrer">programs</a> and hiding them from you, so who&#39;s really in the wrong here? <a href="https://www.amnesty.org/en/latest/campaigns/2015/04/7-reasons-why-ive-got-nothing-to-hide-is-the-wrong-response-to-mass-surveillance/" target="_blank" rel="noopener noreferrer">&quot;Nothing to hide&quot; is an illogical argument</a> because privacy and security are basic human rights, not crimes or luxuries.</p><h3 id="the-green-lock" tabindex="-1">The green lock <a class="header-anchor" href="#the-green-lock" aria-hidden="true">#</a></h3><p>You&#39;ve probably seen the green lock icon in your browser when you visit websites. That green lock tells you that you&#39;re using something called <a href="https://en.wikipedia.org/wiki/HTTPS" target="_blank" rel="noopener noreferrer">HyperText Transfer Protocol Secure (<abbr title="HyperText Transfer Protocol Secure">HTTPS</abbr>)</a>. This is a bit complicated, but for the most part, it means that the data you&#39;re sending and receiving from the websites you visit is encrypted using a protocol called <a href="https://en.wikipedia.org/wiki/Transport_Layer_Security" target="_blank" rel="noopener noreferrer">Transport Layer Security (<abbr title="Transport Layer Security">TLS</abbr>)</a>, formerly known as Secure Sockets Layer (<abbr title="Secure Sockets Layer">SSL</abbr>). Here&#39;s a <a href="https://howhttps.works/https-ssl-tls-differences/" target="_blank" rel="noopener noreferrer">brief explanation of <abbr title="HyperText Transfer Protocol Secure">HTTPS</abbr>, <abbr title="Transport Layer Security">TLS</abbr> and <abbr title="Secure Sockets Layer">SSL</abbr></a>.</p><p>A lot of big words, I know. Don&#39;t worry, it&#39;s a pretty complicated topic that, luckily, you don&#39;t have to understand. All you need to know is that most of your internet activity is encrypted using this stuff, which is mostly why you&#39;re not getting hacked by someone every day. This includes most websites you visit, your instant messengers (excluding SMS), emails, etc. Basically anything you need WiFi or an internet connection to use, it&#39;s probably encrypted using <abbr title="HyperText Transfer Protocol Secure">HTTPS</abbr>.</p><p>However, some websites don&#39;t use <abbr title="HyperText Transfer Protocol Secure">HTTPS</abbr>, and that&#39;s when your browser warns you that there&#39;s a &quot;security risk ahead&quot; or &quot;your connection is not private&quot; or whatever, and you get a cross on the lock icon in the search/URL bar. This means that the data you send and receive from those websites isn&#39;t encrypted, which means that hackers, governments, whoever you&#39;re trying to protect yourself from, will be able to see what you do on that website, if they choose to do so. And as shown by the mass surveillance examples above, they will always choose to do so.</p><h3 id="end-to-end-encryption-e2ee" tabindex="-1">End-to-end encryption (<abbr title="end-to-end encryption">e2ee</abbr>) <a class="header-anchor" href="#end-to-end-encryption-e2ee" aria-hidden="true">#</a></h3><p><a href="https://en.wikipedia.org/wiki/End-to-end_encryption" target="_blank" rel="noopener noreferrer">End-to-end encryption</a> is exactly what it sounds like, your data is encrypted from one end to the other, and no one in the middle is able to access it. It&#39;s also called &quot;<a href="https://tresorit.com/blog/zero-knowledge-encryption/" target="_blank" rel="noopener noreferrer">zero-knowledge encryption</a>&quot; in cases like cloud storage, since the provider has &quot;zero knowledge&quot; about your data.</p><p>It&#39;s arguably the most private and secure form of encryption, since it removes all trust from the provider. In end-to-end encrypted communication, the messages you send are encrypted on your device, sent to the server in encrypted form so they can&#39;t see your messages, and sent to the person you&#39;re talking to from there, where the message is then decrypted so that they can read it. In the case of cloud storage, the data is encrypted on your phone and sent to the server, where it&#39;s stored in its encrypted form. When you need the data back, the server sends it to you, and then you can decrypt it with your private key (your password, usually).</p><p>As you can see, if there is <abbr title="end-to-end encryption">e2ee</abbr>, there is no need to trust the provider, whether that&#39;s the messaging platform, cloud storage provider, etc., that they&#39;re not reading your messages. This also highlights the importance of open source, since we can verify in open source apps if the data is actually being encrypted or not, whereas in closed source apps you need to trust the developers that they actually encrypt the data on your device before sending it to the server.</p><p>Obviously, <abbr title="end-to-end encryption">e2ee</abbr> is quite a bit more complicated than that, but that&#39;s about the gist of it.</p><h2 id="metadata" tabindex="-1">Metadata <a class="header-anchor" href="#metadata" aria-hidden="true">#</a></h2><h3 id="what-is-it" tabindex="-1">What is it? <a class="header-anchor" href="#what-is-it" aria-hidden="true">#</a></h3><p>The simplest way to define metadata is &quot;data about data&quot;.</p><p>Imagine you take a photo of a tree on your phone. The data in this case would be the photo itself: the colors and positions of each pixel in the photo, basically what makes the photo a <strong>photo</strong>. The metadata would be additional information about the photo, like the location you took the photo at, the kind of lens you used, the date and time you took the photo, the ISO and focal length, etc. It&#39;s basically data about the photo.</p><p>In the context of messaging, the message you send, whether that&#39;s text, images, files, videos, audio, whatever, is the data. Everything about the message, like who you&#39;re sending it to, when you&#39;re sending it, when it&#39;s received, what type of data is being sent, etc.</p><div class="info custom-block"><p class="custom-block-title"><a href="https://berty.tech/blog/metadata-mobile-messaging/">Berty</a></p><p>if the data is a letter, the metadata is the envelope and its associated information (address, time, date, size\u2026)</p></div><h3 id="why-should-i-care-1" tabindex="-1">Why should I care? <a class="header-anchor" href="#why-should-i-care-1" aria-hidden="true">#</a></h3><div class="info custom-block"><p class="custom-block-title">Edward Snowden</p><p>Metadata is extraordinarily intrusive. As an analyst, I would prefer to be looking at metadata than looking at content, because it&#39;s quicker and easier, and it doesn&#39;t lie.</p></div><p>Think of it like this: if you see someone having a conversation with a known drug dealer, even if the actual conversation wasn&#39;t heard, there can be some fairly accurate assumptions about what&#39;s going on. Similarly, even if the actual messages are encrypted, metadata about the messages can be incredibly revealing.</p><div class="info custom-block"><p class="custom-block-title"><a href="https://www.eff.org/fr/deeplinks/2013/06/why-metadata-matters">Examples from the EFF</a></p><ul><li>They know you received a call from the local NRA office while it was having a campaign against gun legislation, and then called your senators and congressional representatives immediately after. But the content of those calls remains safe from government intrusion.</li><li>They know you called a gynecologist, spoke for a half hour, and then called the local Planned Parenthood&#39;s number later that day. But nobody knows what you spoke about.</li><li>They know you spoke with an HIV testing service, then your doctor, then your health insurance company in the same hour. But they don&#39;t know what was discussed.</li><li>They know you called the suicide prevention hotline from the Golden Gate Bridge. But the topic of the call remains a secret.</li></ul></div><p>As you can see, it&#39;s pretty easy to figure out what&#39;s going on in someone&#39;s life, even if you don&#39;t know the exact words used in each phone call or conversation.</p><div class="info custom-block"><p class="custom-block-title"><a href="https://abcnews.go.com/blogs/headlines/2014/05/ex-nsa-chief-we-kill-people-based-on-metadata">ex-NSA Chief Gen. Michael Hayden</a></p><p>We kill people based on metadata.</p></div><h3 id="what-can-i-do" tabindex="-1">What can I do? <a class="header-anchor" href="#what-can-i-do" aria-hidden="true">#</a></h3><p>In the case of messaging, the best thing you can do is use privacy-friendly services that either have little to no metadata or encrypt your metadata, like <a href="https://threema.ch/en/blog/posts/metadata" target="_blank" rel="noopener noreferrer">Threema</a>, <a href="https://signal.org/blog/sealed-sender/" target="_blank" rel="noopener noreferrer">Signal</a>, <a href="https://getsession.org/blog/metadata-zero-privacy" target="_blank" rel="noopener noreferrer">Session</a>, etc.</p><p>In the case of your files, there are <a href="https://www.privacyguides.org/metadata-removal-tools/" target="_blank" rel="noopener noreferrer">metadata removal tools</a> you can use before you share them with someone or post them online.</p><p>Whatever you do, minimize metadata.</p><h2 id="get-your-info-here" tabindex="-1">Get your info here <a class="header-anchor" href="#get-your-info-here" aria-hidden="true">#</a></h2><p><a href="https://privacyguides.org" target="_blank" rel="noopener noreferrer">PrivacyGuides</a></p><p><a href="https://alternativeto.net" target="_blank" rel="noopener noreferrer">AlternativeTo</a></p><p><a href="https://tosdr.org" title="Terms of Service; Didn&#39;t Read" target="_blank" rel="noopener noreferrer">ToS;DR</a></p><p><a href="https://techlore.tech" target="_blank" rel="noopener noreferrer">Techlore</a> - also has a <a href="https://www.youtube.com/c/Techlore" target="_blank" rel="noopener noreferrer">YouTube channel</a></p><p><a href="https://thenewoil.org" target="_blank" rel="noopener noreferrer">The New Oil</a> - also has a <a href="https://www.youtube.com/c/TheNewOil" target="_blank" rel="noopener noreferrer">YouTube channel</a></p><p><a href="https://surveillancereport.tech" target="_blank" rel="noopener noreferrer">Surveillance Report</a> - presented by Techlore and The New Oil, also has a <a href="https://www.youtube.com/c/SurveillanceReport" target="_blank" rel="noopener noreferrer">YouTube channel</a></p><p><a href="https://plexus.techlore.tech" target="_blank" rel="noopener noreferrer">Plexus</a></p><p><a href="https://contrachrome.com" target="_blank" rel="noopener noreferrer">Contra Chrome</a> - explains everything wrong with Google Chrome</p><p>You can also join the <a href="https://www.privacyguides.org/#we-need-you-heres-how-to-get-involved" target="_blank" rel="noopener noreferrer">PrivacyGuides</a>, <a href="https://techlore.tech" title="You can find their socials in the top right corner" target="_blank" rel="noopener noreferrer">Techlore</a> and <a href="https://thenewoil.org/links.html" target="_blank" rel="noopener noreferrer">The New Oil</a> communities. They&#39;re super friendly and will help you with whatever privacy- or security-related questions you have.</p>',69),i=[n];function s(h,l,c,p,d,u){return o(),t("div",null,i)}var f=e(a,[["render",s]]);export{g as __pageData,f as default};
